.darma-loader-darma-custom-042 {
  width: 120px;
  height: 22px;
  border-radius: 20px;
  color: var(--loader-color, #514b82);
  border: 2px solid;
  position: relative;
}
.darma-loader-darma-custom-042::before {
  content: "";
  position: absolute;
  margin: 2px;
  inset: 0 100% 0 0;
  border-radius: inherit;
  background: currentColor;
  animation: darma-loader-darma-custom-042-l6 2s infinite;
}
@keyframes darma-loader-darma-custom-042-l6 {
  100% { inset: 0; }
}

